const menuButton = document.querySelector(".menu-button");
const navigation = document.querySelector(".main-nav");
const languageButtons = document.querySelectorAll("[data-lang]");
const metaDescription = document.querySelector("#meta-description");
let currentLanguage = "ro";

function updateMenuLabel() {
  const key = navigation.classList.contains("open") ? "menuClose" : "menuOpen";
  menuButton.setAttribute("aria-label", translations[currentLanguage][key]);
}

function setLanguage(language) {
  if (!translations[language]) return;
  currentLanguage = language;
  const copy = translations[language];
  const isGallery = document.body.dataset.page === "gallery";
  document.documentElement.lang = language;
  document.title = isGallery ? copy.galleryPageTitle : copy.pageTitle;
  metaDescription.setAttribute("content", isGallery ? copy.galleryMetaDescription : copy.metaDescription);
  document.querySelectorAll("[data-i18n]").forEach((element) => {
    const value = copy[element.dataset.i18n];
    if (value) element.textContent = value;
  });
  document.querySelectorAll("[data-i18n-aria]").forEach((element) => {
    const value = copy[element.dataset.i18nAria];
    if (value) element.setAttribute("aria-label", value);
  });
  document.querySelectorAll("[data-i18n-title]").forEach((element) => {
    const value = copy[element.dataset.i18nTitle];
    if (value) element.setAttribute("title", value);
  });
  languageButtons.forEach((button) => {
    const active = button.dataset.lang === language;
    button.classList.toggle("active", active);
    button.setAttribute("aria-pressed", String(active));
  });
  updateMenuLabel();
  localStorage.setItem("momentum-language", language);
}

function closeMenu() {
  navigation.classList.remove("open");
  document.body.classList.remove("menu-open");
  menuButton.setAttribute("aria-expanded", "false");
  updateMenuLabel();
}

menuButton.addEventListener("click", () => {
  const open = navigation.classList.toggle("open");
  document.body.classList.toggle("menu-open", open);
  menuButton.setAttribute("aria-expanded", String(open));
  updateMenuLabel();
});

navigation.querySelectorAll("a").forEach((link) => link.addEventListener("click", closeMenu));
languageButtons.forEach((button) => button.addEventListener("click", () => setLanguage(button.dataset.lang)));
document.addEventListener("keydown", (event) => { if (event.key === "Escape") closeMenu(); });

if ("IntersectionObserver" in window && document.body.dataset.page !== "gallery") {
  const links = document.querySelectorAll(".main-nav > a");
  const observer = new IntersectionObserver((entries) => {
    entries.forEach((entry) => {
      if (!entry.isIntersecting) return;
      links.forEach((link) => link.classList.toggle("active", link.getAttribute("href") === `#${entry.target.id}`));
    });
  }, { rootMargin: "-35% 0px -58%", threshold: 0 });
  document.querySelectorAll("main section[id]").forEach((section) => observer.observe(section));
}

document.getElementById("year").textContent = new Date().getFullYear();
const savedLanguage = localStorage.getItem("momentum-language");
setLanguage(translations[savedLanguage] ? savedLanguage : "ro");
